// TC18: input { totalWatts: 1000, voltage: '110v', phase: 'single_phase', continuousLoad: 'false' } → continuousLoad string 'false' is truthy → output { total: 11.36, breakdown: ... } (since Boolean('false') = true) — acceptable; validation does not restrict to boolean only.
// TC19: input { totalWatts: 5000, voltage: '220v', phase: 'three phase', continuousLoad: false } → output { total: 13.12, breakdown: ... } (spacing replaced)
// TC20: input { totalWatts: NaN, voltage: '110v', phase: 'single_phase', continuousLoad: false } → output { error: "Total watts must be a number." }

const calculator = {
  normalize(inputs) {
    // Normalize voltage
    let voltage = String(inputs.voltage || '').toLowerCase().replace(/[ _-]+/g, '_');
    if (voltage === '110' || voltage === '110v') voltage = '110v';
    else if (voltage === '220' || voltage === '220v') voltage = '220v';

    // Normalize phase
    let phase = String(inputs.phase || '').toLowerCase().replace(/[ _-]+/g, '_');
    if (phase === 'single_phase' || phase === 'single') phase = 'single_phase';
    else if (phase === 'three_phase' || phase === 'three') phase = 'three_phase';

    const totalWatts = Number(inputs.totalWatts);
    const continuousLoad = Boolean(inputs.continuousLoad);

    return { totalWatts, voltage, phase, continuousLoad };
  },

  validate(normalized) {
    const errors = [];
    if (isNaN(normalized.totalWatts)) {
      errors.push('Total watts must be a number.');
    } else if (normalized.totalWatts <= 0) {
      errors.push('Total watts must be greater than zero.');
    }
    if (!['110v', '220v'].includes(normalized.voltage)) {
      errors.push('Invalid voltage. Must be 110V or 220V.');
    }
    if (!['single_phase', 'three_phase'].includes(normalized.phase)) {
      errors.push('Invalid phase. Must be single_phase or three_phase.');
    }
    return errors;
  },

  calculate(inputs) {
    const normalized = this.normalize(inputs);
    const errors = this.validate(normalized);
    if (errors.length > 0) {
      return { error: errors.join('; ') };
    }

    const { totalWatts, voltage, phase, continuousLoad } = normalized;
    const voltageValue = voltage === '110v' ? 110 : 220;
    let baseCurrent;
    if (phase === 'single_phase') {
      baseCurrent = totalWatts / voltageValue;
    } else { // three_phase
      baseCurrent = totalWatts / (voltageValue * Math.sqrt(3));
    }

    const multiplier = continuousLoad ? 1.25 : 1;
    const adjustedCurrent = baseCurrent * multiplier;

    return {
      total: Number(adjustedCurrent.toFixed(2)),
      breakdown: {
        totalWatts: totalWatts,
        voltage: voltage,
        phase: phase,
        baseCurrent: Number(baseCurrent.toFixed(2)),
        continuousLoad: continuousLoad,
        multiplier: multiplier,
        adjustedCurrent: Number(adjustedCurrent.toFixed(2))
      }
    };
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  }
};

const CALC_PARAMS = [
  {
    name: 'totalWatts',
    label: 'Total Watts',
    type: 'number',
    placeholder: 'e.g. 5000'
  },
  {
    name: 'voltage',
    label: 'Voltage',
    type: 'select',
    options: [['110v', '110V'], ['220v', '220V']]
  },
  {
    name: 'phase',
    label: 'Phase',
    type: 'select',
    options: [['single_phase', 'Single Phase'], ['three_phase', 'Three Phase']]
  },
  {
    name: 'continuousLoad',
    label: 'Continuous Load (3+ hours)?',
    type: 'checkbox'
  }
];
